#include<bits/stdc++.h>
using namespace std;
int dep[200010],siz[200010],fa[200010],w[200010],n;
vector<int> mp[200010];
void dfs(int x)
{
    siz[x]=1;
    dep[x]=dep[fa[x]]+1;
    for(int i:mp[x])
    {
        dfs(i);
        siz[x]+=siz[i];
    }
}
struct node
{
    int w,dep,siz;
    bool operator<(const node&b)const
    {
        return (siz-w-dep)>(b.siz-b.w-b.dep);
    }
}a[200010];
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&w[i]);
    }
    for(int i=2;i<=n;i++)
    {
        scanf("%d",&fa[i]);
        mp[fa[i]].push_back(i);
    }
    dfs(1);
    for(int i=1;i<=n;i++)
    {
        a[i].dep=dep[i];
        a[i].w=w[i];
        a[i].siz=siz[i];
    }
    sort(a+1,a+1+n);
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        if(i%2==1)
        {
            ans+=a[i].siz-a[i].w-a[i].dep;
        }
    }
    printf("%lld",ans);
    return 0;
}
